FILES = {'backend/app/core/config.py': 'from functools import lru_cache\n\nfrom pydantic import Field\nfrom pydantic_settings import BaseSettings, SettingsConfigDict\n\n\nclass Settings(BaseSettings):\n    """Application settings loaded from environment variables."""\n\n    app_name: str = Field(default="Missio", alias="MISSIO_APP_NAME")\n    environment: str = Field(default="local", alias="MISSIO_ENVIRONMENT")\n    debug: bool = Field(default=True, alias="MISSIO_DEBUG")\n    default_timezone: str = Field(\n        default="Europe/Istanbul",\n        alias="MISSIO_DEFAULT_TIMEZONE",\n    )\n    database_url: str = Field(\n        default="sqlite:///./missio_local.db",\n        alias="MISSIO_DATABASE_URL",\n    )\n    secret_key: str = Field(\n        default="change-this-secret-key-before-production",\n        alias="MISSIO_SECRET_KEY",\n    )\n    access_token_expire_minutes: int = Field(\n        default=60,\n        alias="MISSIO_ACCESS_TOKEN_EXPIRE_MINUTES",\n    )\n    rate_limit_enabled: bool = Field(\n        default=True,\n        alias="MISSIO_RATE_LIMIT_ENABLED",\n    )\n    rate_limit_max_requests: int = Field(\n        default=120,\n        alias="MISSIO_RATE_LIMIT_MAX_REQUESTS",\n    )\n    rate_limit_window_seconds: int = Field(\n        default=60,\n        alias="MISSIO_RATE_LIMIT_WINDOW_SECONDS",\n    )\n\n    model_config = SettingsConfigDict(\n        env_file=".env",\n        env_file_encoding="utf-8",\n        extra="ignore",\n    )\n\n\n@lru_cache\ndef get_settings() -> Settings:\n    """Return cached application settings."""\n\n    return Settings()\n\n\nsettings = get_settings()\n', 'backend/.env.example': 'MISSIO_APP_NAME=Missio\nMISSIO_ENVIRONMENT=local\nMISSIO_DEBUG=true\nMISSIO_DEFAULT_TIMEZONE=Europe/Istanbul\nMISSIO_DATABASE_URL=sqlite:///./missio_local.db\nMISSIO_SECRET_KEY=change-this-secret-key-before-production\nMISSIO_ACCESS_TOKEN_EXPIRE_MINUTES=60\nMISSIO_RATE_LIMIT_ENABLED=true\nMISSIO_RATE_LIMIT_MAX_REQUESTS=120\nMISSIO_RATE_LIMIT_WINDOW_SECONDS=60\n', 'backend/app/core/rate_limit.py': 'from __future__ import annotations\n\nimport time\nfrom collections import defaultdict, deque\nfrom collections.abc import Awaitable, Callable\nfrom threading import Lock\n\nfrom fastapi.responses import JSONResponse\nfrom starlette.requests import Request\nfrom starlette.responses import Response\n\nfrom app.core.config import settings\n\n\nRATE_LIMIT_STATE: dict[str, deque[float]] = defaultdict(deque)\nRATE_LIMIT_LOCK = Lock()\n\nEXEMPT_PATHS = {\n    "/",\n    "/api/v1/health",\n}\n\n\ndef clear_rate_limit_state() -> None:\n    """Clear in-memory rate limit state."""\n\n    with RATE_LIMIT_LOCK:\n        RATE_LIMIT_STATE.clear()\n\n\ndef get_client_identifier(request: Request) -> str:\n    """Return best-effort client identifier."""\n\n    forwarded_for = request.headers.get("x-forwarded-for")\n\n    if forwarded_for:\n        first_ip = forwarded_for.split(",")[0].strip()\n\n        if first_ip:\n            return first_ip[:100]\n\n    if request.client is not None and request.client.host:\n        return request.client.host[:100]\n\n    return "unknown"\n\n\ndef get_rate_limit_key(request: Request) -> str:\n    """Build rate limit key from client and request path."""\n\n    client_identifier = get_client_identifier(request)\n    path = request.url.path\n\n    return f"{client_identifier}:{path}"\n\n\ndef should_skip_rate_limit(request: Request) -> bool:\n    """Return whether request should bypass rate limiting."""\n\n    if not settings.rate_limit_enabled:\n        return True\n\n    if request.url.path in EXEMPT_PATHS:\n        return True\n\n    return False\n\n\ndef prune_old_requests(\n    request_times: deque[float],\n    *,\n    now: float,\n    window_seconds: int,\n) -> None:\n    """Remove request timestamps outside the rate limit window."""\n\n    cutoff = now - window_seconds\n\n    while request_times and request_times[0] <= cutoff:\n        request_times.popleft()\n\n\ndef build_rate_limit_response(retry_after_seconds: int) -> JSONResponse:\n    """Build safe rate limit response."""\n\n    response = JSONResponse(\n        status_code=429,\n        content={\n            "detail": "Çok fazla istek gönderildi. Lütfen daha sonra tekrar deneyin.",\n        },\n    )\n    response.headers["Retry-After"] = str(max(retry_after_seconds, 1))\n    response.headers["X-RateLimit-Limit"] = str(settings.rate_limit_max_requests)\n    response.headers["X-RateLimit-Remaining"] = "0"\n\n    return response\n\n\nasync def add_rate_limit(\n    request: Request,\n    call_next: Callable[[Request], Awaitable[Response]],\n) -> Response:\n    """Apply simple in-memory rate limiting."""\n\n    if should_skip_rate_limit(request):\n        return await call_next(request)\n\n    now = time.monotonic()\n    key = get_rate_limit_key(request)\n    max_requests = settings.rate_limit_max_requests\n    window_seconds = settings.rate_limit_window_seconds\n\n    if max_requests <= 0 or window_seconds <= 0:\n        return await call_next(request)\n\n    with RATE_LIMIT_LOCK:\n        request_times = RATE_LIMIT_STATE[key]\n        prune_old_requests(\n            request_times,\n            now=now,\n            window_seconds=window_seconds,\n        )\n\n        if len(request_times) >= max_requests:\n            oldest_request = request_times[0]\n            retry_after = int((oldest_request + window_seconds) - now) + 1\n\n            return build_rate_limit_response(retry_after)\n\n        request_times.append(now)\n        remaining = max(max_requests - len(request_times), 0)\n\n    response = await call_next(request)\n    response.headers.setdefault("X-RateLimit-Limit", str(max_requests))\n    response.headers.setdefault("X-RateLimit-Remaining", str(remaining))\n\n    return response\n', 'backend/app/main.py': 'from fastapi import FastAPI\nfrom fastapi.middleware.cors import CORSMiddleware\n\nfrom app.api.router import api_router\nfrom app.core.config import settings\nfrom app.core.http_security import add_security_headers\nfrom app.core.rate_limit import add_rate_limit\nfrom app.core.security_config import is_production_environment\n\n\ndef create_app() -> FastAPI:\n    """Create and configure the FastAPI application."""\n\n    is_production = is_production_environment(settings.environment)\n\n    app = FastAPI(\n        title=settings.app_name,\n        debug=settings.debug,\n        version="0.1.0",\n        description="Missio - Mission is possible.",\n        docs_url=None if is_production else "/docs",\n        redoc_url=None if is_production else "/redoc",\n        openapi_url=None if is_production else "/openapi.json",\n    )\n\n    app.middleware("http")(add_security_headers)\n    app.middleware("http")(add_rate_limit)\n\n    app.add_middleware(\n        CORSMiddleware,\n        allow_origins=[\n            "http://localhost:5173",\n            "http://127.0.0.1:5173",\n        ],\n        allow_credentials=True,\n        allow_methods=["*"],\n        allow_headers=["*"],\n    )\n\n    app.include_router(api_router)\n\n    @app.get("/")\n    def root() -> dict[str, str]:\n        return {\n            "message": "Missio backend is running.",\n            "slogan": "Mission is possible.",\n        }\n\n    return app\n\n\napp = create_app()\n', 'backend/app/commands/check_rate_limit_security.py': 'from __future__ import annotations\n\nfrom fastapi.testclient import TestClient\n\nfrom app.core.config import settings\nfrom app.core.rate_limit import clear_rate_limit_state\nfrom app.main import app\n\n\ndef main() -> None:\n    """Run rate limit smoke checks."""\n\n    original_enabled = settings.rate_limit_enabled\n    original_max_requests = settings.rate_limit_max_requests\n    original_window_seconds = settings.rate_limit_window_seconds\n\n    settings.rate_limit_enabled = True\n    settings.rate_limit_max_requests = 2\n    settings.rate_limit_window_seconds = 60\n    clear_rate_limit_state()\n\n    client = TestClient(app)\n    headers = {"x-forwarded-for": "203.0.113.10"}\n\n    try:\n        first_response = client.get("/api/v1/auth/me", headers=headers)\n        second_response = client.get("/api/v1/auth/me", headers=headers)\n        third_response = client.get("/api/v1/auth/me", headers=headers)\n\n        if first_response.status_code != 401:\n            raise RuntimeError("İlk istek auth nedeniyle 401 dönmeliydi.")\n\n        if second_response.status_code != 401:\n            raise RuntimeError("İkinci istek auth nedeniyle 401 dönmeliydi.")\n\n        if third_response.status_code != 429:\n            raise RuntimeError("Üçüncü istek rate limit nedeniyle 429 dönmeliydi.")\n\n        if third_response.headers.get("retry-after") is None:\n            raise RuntimeError("Rate limit response Retry-After header içermiyor.")\n\n        print("Rate limit bloklama kontrolü başarılı.")\n        print("Retry-After header kontrolü başarılı.")\n        print("Rate limit güvenlik temel kontrolü başarılı.")\n    finally:\n        settings.rate_limit_enabled = original_enabled\n        settings.rate_limit_max_requests = original_max_requests\n        settings.rate_limit_window_seconds = original_window_seconds\n        clear_rate_limit_state()\n\n\nif __name__ == "__main__":\n    main()\n', 'backend/tests/test_rate_limit.py': 'from fastapi.testclient import TestClient\n\nfrom app.core.config import settings\nfrom app.core.rate_limit import clear_rate_limit_state\nfrom app.main import app\n\n\ndef test_rate_limit_blocks_after_configured_limit() -> None:\n    original_enabled = settings.rate_limit_enabled\n    original_max_requests = settings.rate_limit_max_requests\n    original_window_seconds = settings.rate_limit_window_seconds\n\n    settings.rate_limit_enabled = True\n    settings.rate_limit_max_requests = 2\n    settings.rate_limit_window_seconds = 60\n    clear_rate_limit_state()\n\n    client = TestClient(app)\n    headers = {"x-forwarded-for": "198.51.100.1"}\n\n    try:\n        first_response = client.get("/api/v1/auth/me", headers=headers)\n        second_response = client.get("/api/v1/auth/me", headers=headers)\n        third_response = client.get("/api/v1/auth/me", headers=headers)\n\n        assert first_response.status_code == 401\n        assert second_response.status_code == 401\n        assert third_response.status_code == 429\n        assert third_response.headers["retry-after"]\n        assert third_response.headers["x-ratelimit-remaining"] == "0"\n    finally:\n        settings.rate_limit_enabled = original_enabled\n        settings.rate_limit_max_requests = original_max_requests\n        settings.rate_limit_window_seconds = original_window_seconds\n        clear_rate_limit_state()\n\n\ndef test_rate_limit_uses_client_ip_isolation() -> None:\n    original_enabled = settings.rate_limit_enabled\n    original_max_requests = settings.rate_limit_max_requests\n    original_window_seconds = settings.rate_limit_window_seconds\n\n    settings.rate_limit_enabled = True\n    settings.rate_limit_max_requests = 1\n    settings.rate_limit_window_seconds = 60\n    clear_rate_limit_state()\n\n    client = TestClient(app)\n\n    try:\n        first_client_response = client.get(\n            "/api/v1/auth/me",\n            headers={"x-forwarded-for": "198.51.100.2"},\n        )\n        second_client_response = client.get(\n            "/api/v1/auth/me",\n            headers={"x-forwarded-for": "198.51.100.3"},\n        )\n\n        assert first_client_response.status_code == 401\n        assert second_client_response.status_code == 401\n    finally:\n        settings.rate_limit_enabled = original_enabled\n        settings.rate_limit_max_requests = original_max_requests\n        settings.rate_limit_window_seconds = original_window_seconds\n        clear_rate_limit_state()\n\n\ndef test_rate_limit_can_be_disabled() -> None:\n    original_enabled = settings.rate_limit_enabled\n    original_max_requests = settings.rate_limit_max_requests\n    original_window_seconds = settings.rate_limit_window_seconds\n\n    settings.rate_limit_enabled = False\n    settings.rate_limit_max_requests = 1\n    settings.rate_limit_window_seconds = 60\n    clear_rate_limit_state()\n\n    client = TestClient(app)\n    headers = {"x-forwarded-for": "198.51.100.4"}\n\n    try:\n        first_response = client.get("/api/v1/auth/me", headers=headers)\n        second_response = client.get("/api/v1/auth/me", headers=headers)\n\n        assert first_response.status_code == 401\n        assert second_response.status_code == 401\n    finally:\n        settings.rate_limit_enabled = original_enabled\n        settings.rate_limit_max_requests = original_max_requests\n        settings.rate_limit_window_seconds = original_window_seconds\n        clear_rate_limit_state()\n', 'docs/API_SECURITY.md': "# Missio API Security\n\nBu doküman Missio API yüzeyinin güvenlik sınıflandırmasını tutar.\n\n---\n\n## 1. Public Endpoint Listesi\n\nAşağıdaki endpointler token olmadan çalışabilir:\n\n| Method | Endpoint | Amaç |\n|---|---|---|\n| GET | `/` | Basit uygulama çalışma kontrolü |\n| GET | `/api/v1/health` | Basit servis sağlık kontrolü |\n| POST | `/api/v1/auth/login` | Kullanıcı girişi |\n\nPublic endpointler hassas veri döndürmemelidir.\n\n---\n\n## 2. Protected Endpoint Listesi\n\nAşağıdaki endpointler token ister:\n\n| Method | Endpoint | Yetki |\n|---|---|---|\n| GET | `/api/v1/auth/me` | Giriş yapmış kullanıcı |\n| GET | `/api/v1/db/health` | Sadece `super_admin` |\n\n---\n\n## 3. API Güvenlik Kuralları\n\n- Public olmayan endpointler token istemelidir.\n- Protected endpointlerde rol kontrolü yapılmalıdır.\n- Business scope gerektiren endpointlerde `business_id` kontrolü yapılmalıdır.\n- `password_hash`, secret veya gereksiz hassas veri response içinde dönmemelidir.\n- Hata cevaplarında stack trace veya teknik detay dönmemelidir.\n- API response'larında güvenlik headerları bulunmalıdır.\n- API response'ları için `Cache-Control: no-store` kullanılmalıdır.\n- Production ortamda `/docs`, `/redoc` ve `/openapi.json` kapatılmalıdır.\n- API rate limit aktif olmalıdır.\n\n---\n\n## 4. Rate Limit\n\nMissio ilk sürümde uygulama içi basit rate limit kullanır.\n\nVarsayılan ayarlar:\n\n```text\nMISSIO_RATE_LIMIT_ENABLED=true\nMISSIO_RATE_LIMIT_MAX_REQUESTS=120\nMISSIO_RATE_LIMIT_WINDOW_SECONDS=60\n```\n\nNotlar:\n\n- Rate limit client IP ve path bazlı uygulanır.\n- `/` ve `/api/v1/health` rate limit dışındadır.\n- Limit aşılırsa HTTP 429 döner.\n- Response içinde `Retry-After` headerı bulunur.\n- Bu yapı tek process müşteri bazlı kurulum için yeterlidir.\n- İleride merkezi SaaS yapısına geçilirse Redis tabanlı distributed rate limit değerlendirilmelidir.\n\n---\n\n## 5. Mevcut API Güvenlik Testleri\n\nTest dosyaları:\n\n```text\nbackend/tests/test_api_security.py\nbackend/tests/test_rate_limit.py\n```\n\nKontrol komutu:\n\n```powershell\npython -m app.commands.check_api_security\npython -m app.commands.check_rate_limit_security\npython -m pytest tests/test_api_security.py tests/test_rate_limit.py\n```\n"}

CHECKLIST_REPLACEMENTS = {
    "- [ ] Rate limit eklenecek.": "- [x] Rate limit eklenecek.",
}


def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def update_security_checklist() -> None:
    if not SECURITY_CHECKLIST_PATH.exists():
        print("SECURITY_CHECKLIST.md bulunamadi, atlandi.")
        return

    content = SECURITY_CHECKLIST_PATH.read_text(encoding="utf-8")

    for old, new in CHECKLIST_REPLACEMENTS.items():
        content = content.replace(old, new)

    SECURITY_CHECKLIST_PATH.write_text(content, encoding="utf-8")
    print("SECURITY_CHECKLIST.md guncellendi.")


def compile_files() -> None:
    for relative_path in FILES:
        if relative_path.endswith(".py"):
            py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("Python syntax kontrolu basarili.")


def main() -> None:
    print("Missio ADIM 5I API rate limit temeli olusturuluyor.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)

    update_security_checklist()
    compile_files()

    print("")
    print("Tamamlandi.")


if __name__ == "__main__":
    main()
